	router.Post(options.BaseURL+"/data/multipart/complete", wrapper.InternalMultipartComplete)

	router.Post(options.BaseURL+"/data/multipart/init", wrapper.InternalMultipartInit)

	router.Post(options.BaseURL+"/data/multipart/upload", wrapper.InternalMultipartUpload)

	router.Post(options.BaseURL+"/data/upload", wrapper.InternalUploadBlank)

	router.Post(options.BaseURL+"/data/upload/bulk", wrapper.InternalUploadBulk)

	router.Get(options.BaseURL+"/data/upload/:file_id", wrapper.InternalUploadURL)

	router.Delete(options.BaseURL+"/index", wrapper.InternalDeleteByQuery)

	router.Get(options.BaseURL+"/index", wrapper.InternalList)

	router.Post(options.BaseURL+"/index", wrapper.InternalCreate)

	router.Post(options.BaseURL+"/index/bulk", wrapper.InternalBulkCreate)

	router.Post(options.BaseURL+"/index/bulk/delete", wrapper.InternalBulkDeleteHashes)

	router.Post(options.BaseURL+"/index/bulk/documents", wrapper.InternalBulkDocuments)

	router.Post(options.BaseURL+"/index/bulk/hashes", wrapper.InternalBulkHashes)

	router.Post(options.BaseURL+"/index/bulk/sha256/validity", wrapper.InternalBulkSHA256Validity)

	router.Delete(options.BaseURL+"/index/:id", wrapper.InternalDelete)

